342	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
343	/// retriever/director lifecycle) call this as their first step. The helper
344	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
345	/// already match the throwaway markers, returns `Ok(())` with no side
346	/// effect. Otherwise rewrites both lines in place, then `git add` +
347	/// `git commit` the change. One commit per fixture run regardless of which
348	/// case is the first to call it.
349	///
350	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
351	/// matching the pristine fixture's start-over-from-zero failure mode.
352	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
353	    let rbrr = root.join(RBTDRP_RBRR_FILE);
354	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
355	    let runtime =
356	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
357	
358	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
359	        return Ok(());
360	    }
361	
362	    let content = std::fs::read_to_string(&rbrr)
363	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
364	    let new_content = rbtdrp_replace_env_fields(
365	        &content,
366	        &[
367	            (RBTDRP_FIELD_RBRR_CLOUD_PREFIX, RBTDRP_THROWAWAY_CLOUD_PREFIX),
